const importPromises = {};
const iconTemplateCache = {};
export function hasIconLibrary(dir, category) {
    const cacheKey = makeCacheKey(dir, category);
    return !!iconTemplateCache[cacheKey];
}
export function getIconLibrary(dir, category) {
    const cacheKey = makeCacheKey(dir, category);
    return iconTemplateCache[cacheKey] || null;
}
export function fetchIconLibrary(dir, category) {
    const cacheKey = makeCacheKey(dir, category);
    if (importPromises[cacheKey]) {
        return importPromises[cacheKey];
    }
    const promise = fetchIconTemplate(dir, category);
    promise
        .then((tmpl) => {
        iconTemplateCache[cacheKey] = tmpl;
        delete importPromises[cacheKey];
    })
        .catch(() => {
        delete importPromises[cacheKey];
    });
    importPromises[cacheKey] = promise;
    return promise;
}
function makeCacheKey(dir, category) {
    return `${category}${dir}`;
}
async function fetchIconTemplate(dir, category) {
    if (dir === 'rtl') {
        switch (category) {
            case 'utility': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesUtilityRtl');
                return Lib;
            }
            case 'action': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesActionRtl');
                return Lib;
            }
            case 'standard': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesStandardRtl');
                return Lib;
            }
            case 'doctype': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesDoctypeRtl');
                return Lib;
            }
            case 'custom': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesCustomRtl');
                return Lib;
            }
            default:
                return null;
        }
    }
    else {
        switch (category) {
            case 'utility': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesUtility');
                return Lib;
            }
            case 'action': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesAction');
                return Lib;
            }
            case 'standard': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesStandard');
                return Lib;
            }
            case 'doctype': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesDoctype');
                return Lib;
            }
            case 'custom': {
                const { default: Lib } = await import('lightning/iconSvgTemplatesCustom');
                return Lib;
            }
            default:
                return null;
        }
    }
}
